--// SquidNoMo
--// 1.1 beta 1
--// Theme.lua
--//========================================================--

local Environment = _G
if type(getgenv) == "function" then
    local ok, result = pcall(getgenv)
    if ok and type(result) == "table" then
        Environment = result
    end
