local function apply(object)
    if not object:IsA("Atmosphere") then return end
    if not States[object] then
        States[object] = {
            Density = object.Density,
            Haze = object.Haze,
            Glare = object.Glare,
        }
    end
    object.Density = 0
    object.Haze = 0
    object.Glare = 0
end

